# Tests des validations de variables (échouer tôt, sans toucher AWS).
# command = plan : la validation échoue avant tout appel provider -> creds-free.
# mock_provider en filet : garantit l'absence de credential même si le plan progresse.
# Un run atomique par validateur -> message d'erreur isolé, relecture simple (tip live).

mock_provider "aws" {}

run "bucket_name_too_short" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  variables {
    bucket_name = "ab"
    environment = "dev"
  }
  expect_failures = [var.bucket_name]
}

run "bucket_name_invalid_chars" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  variables {
    bucket_name = "Mon_Bucket"
    environment = "dev"
  }
  expect_failures = [var.bucket_name]
}

run "invalid_environment" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  variables {
    bucket_name = "valid-bucket-name"
    environment = "production"
  }
  expect_failures = [var.environment]
}

run "encryption_requires_kms_key" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  variables {
    bucket_name       = "valid-bucket-name"
    environment       = "dev"
    enable_encryption = true
    kms_key_arn       = null
  }
  expect_failures = [var.enable_encryption]
}

run "prod_forbids_force_destroy" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  variables {
    bucket_name   = "valid-bucket-name"
    environment   = "prod"
    force_destroy = true
  }
  expect_failures = [var.force_destroy]
}

# Tests de plan : prouver que les variables se câblent dans la config planifiée.
# mock_provider -> aucun credential, rapide, tourne en CI sans secret.
# Le bloc variables au niveau fichier pose les valeurs par défaut de TOUS les run (tip live).

mock_provider "aws" {}

variables {
  bucket_name = "demo-plan-bucket"
  environment = "dev"
}

run "versioning_enabled_by_default" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  assert {
    condition     = aws_s3_bucket_versioning.this.versioning_configuration[0].status == "Enabled"
    error_message = "versioning should default to Enabled"
  }
}

run "public_access_fully_blocked" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  assert {
    condition = (
      aws_s3_bucket_public_access_block.this.block_public_acls &&
      aws_s3_bucket_public_access_block.this.block_public_policy &&
      aws_s3_bucket_public_access_block.this.ignore_public_acls &&
      aws_s3_bucket_public_access_block.this.restrict_public_buckets
    )
    error_message = "all four public access block flags must be true"
  }
}

run "no_encryption_block_without_key" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  variables {
    enable_encryption = false
    kms_key_arn       = null
  }
  assert {
    condition     = length(aws_s3_bucket_server_side_encryption_configuration.this) == 0
    error_message = "encryption config must be absent when no KMS key is provided"
  }
}

run "encryption_block_present_with_key" {
  command = plan
  module {
    source = "./modules/s3-bucket"
  }
  variables {
    enable_encryption = true
    kms_key_arn       = "arn:aws:kms:eu-west-1:111122223333:key/demo-key"
  }
  assert {
    condition     = length(aws_s3_bucket_server_side_encryption_configuration.this) == 1
    error_message = "encryption config must be present when a KMS key is provided"
  }
  assert {
    condition     = one(aws_s3_bucket_server_side_encryption_configuration.this[0].rule).apply_server_side_encryption_by_default[0].kms_master_key_id == "arn:aws:kms:eu-west-1:111122223333:key/demo-key"
    error_message = "the provided KMS key ARN must propagate to the encryption rule"
  }
}

# Test d'intégration : déployer l'exemple sur AWS reel (profil sandbox) et asserter
# les valeurs des ressources. terraform test detruit tout en fin de fichier.
# Requiert des credentials AWS (AWS_PROFILE=sandbox). Le suffixe aléatoire rend le
# nom de bucket globalement unique.

run "setup" {
  module {
    source = "./tests/setup"
  }
}

run "deploy_and_assert" {
  command = apply

  variables {
    bucket_name        = "bga-tftest-${run.setup.suffix}"
    environment        = "dev"
    versioning_enabled = true
    force_destroy      = true
  }

  assert {
    condition     = output.bucket_id == "bga-tftest-${run.setup.suffix}"
    error_message = "deployed bucket id must match the requested name"
  }

  assert {
    condition     = output.versioning_status == "Enabled"
    error_message = "versioning must be Enabled on the deployed bucket"
  }

  assert {
    condition     = output.encryption_enabled == false
    error_message = "encryption must be off when no KMS key is provided"
  }
}

# Parallélisme : déployer l'exemple deux fois en parallèle sans collision.
# state_key distinct -> état isolé -> les runs s'exécutent concurremment (>= 1.12).
# Requiert des credentials AWS (AWS_PROFILE=sandbox).

run "setup" {
  module {
    source = "./tests/setup"
  }
}

# Variables communes
variables {
  environment   = "dev"
  force_destroy = true
}

run "deploy_a" {
  command   = apply
  parallel  = true
  state_key = "a"
  variables {
    bucket_name = "bga-tftest-a-${run.setup.suffix}"
  }
  assert {
    condition     = output.bucket_id == "bga-tftest-a-${run.setup.suffix}"
    error_message = "bucket A name mismatch"
  }
}

run "deploy_b" {
  command   = apply
  parallel  = true
  state_key = "b"
  variables {
    bucket_name   = "bga-tftest-b-${run.setup.suffix}"
  }
  assert {
    condition     = output.bucket_id == "bga-tftest-b-${run.setup.suffix}"
    error_message = "bucket B name mismatch"
  }
}

# Parallelism: deploy the example twice in parallel without collision.
# Distinct state_key -> isolated state (1.11+); parallel = true runs them concurrently (1.12+).
# Requires AWS credentials (AWS_PROFILE=sandbox).

run "setup" {
  module {
    source = "./tests/setup"
  }
}

# Variables communes
variables {
  environment   = "dev"
  force_destroy = true
}

run "deploy_a" {
  command   = apply
  parallel  = true
  state_key = "a"
  variables {
